'use client';

/**
 * Componente: ResultsDisplay
 * Muestra resultados finales del test
 */

import { TestResult } from '@/lib/types';
import { useRouter } from 'next/navigation';

interface ResultsDisplayProps {
  results: TestResult;
}

export default function ResultsDisplay({ results }: ResultsDisplayProps) {
  const router = useRouter();

  const getEvaluationColor = (evaluation: string) => {
    switch (evaluation) {
      case 'EXCELENTE':
        return 'text-green-600';
      case 'BIEN':
        return 'text-blue-600';
      case 'REGULAR':
        return 'text-yellow-600';
      case 'NECESITA_MEJORA':
        return 'text-red-600';
      default:
        return 'text-gray-600';
    }
  };

  const getPercentageColor = (percentage: number) => {
    if (percentage >= 90) return 'bg-green-100 text-green-800';
    if (percentage >= 75) return 'bg-blue-100 text-blue-800';
    if (percentage >= 60) return 'bg-yellow-100 text-yellow-800';
    return 'bg-red-100 text-red-800';
  };

  return (
    <div className="min-h-screen bg-black p-4 font-mono text-sm text-green-300">
      <div className="max-w-2xl mx-auto">
        {/* Header */}
        <div className="mb-1">$ java -jar tests.jar --results</div>
        <div className="mb-4 text-green-500">TEST COMPLETADO</div>

        {/* Resultados */}
        <div className="mb-4">
          {/* Puntuación */}
          <div className="mb-2">
            <div className="font-bold text-yellow-600">{results.percentage}% [{results.score}/{results.totalQuestions}]</div>
          </div>

          {/* Evaluación */}
          <div className="mb-4 pb-2 border-b border-green-300">
            <h2 className={`font-bold ${getEvaluationColor(results.evaluation)}`}>
              {results.evaluation}
            </h2>
          </div>

          {/* Conceptos débiles */}
          {results.weakConcepts.length > 0 && (
            <div className="mb-4">
              <div className="text-green-500 font-bold mb-2">[ POR MEJORAR ]</div>
              <div className="space-y-1 ml-2 text-sm">
                {results.weakConcepts.map((concept) => (
                  <div key={concept}>
                    - {concept}
                    {results.suggestions[concept] && (
                      <div className="text-xs text-yellow-600 ml-2">{results.suggestions[concept]}</div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          )}

          {results.weakConcepts.length === 0 && (
            <div className="mb-4 text-green-500">
              ✓ Dominas todos los conceptos
            </div>
          )}
        </div>

        {/* Información */}
        <div className="text-xs mb-4 pb-2 border-b border-green-300">
          <div>{results.userName}</div>
          <div>{new Date(results.completedAt).toLocaleString()}</div>
        </div>

        {/* Botones */}
        <div className="flex gap-2">
          <button
            onClick={() => router.push('/')}
            className="px-2 py-1 text-green-300 hover:bg-green-300 hover:text-black transition font-mono text-sm"
          >
            [MENU]
          </button>
          <button
            onClick={() => window.print()}
            className="px-2 py-1 text-green-300 hover:bg-green-300 hover:text-black transition font-mono text-sm"
          >
            [IMPRIMIR]
          </button>
        </div>
      </div>
    </div>
  );
}
